function findSmallestNum(pattern) {
    let num = "123456789";
    for (let i = 0; i < pattern.length; ++i) {
        if (pattern[i] === 'D') {
            let j = i;
            while (j < pattern.length && pattern[j] === 'D') {
                ++j;
